INSERT INTO msxdb_company VALUES ('172','Wolfteam','','0','JP','','Wolfteam started as an internal development team at Telenet Japan in 1986 working on games like Valis and Final Zone. In July 1990, at a time Telenet vastly expanded its development and porting effort, Wolfteam was folded back into Telenet. Furthermore Wolfteam was merged with an other Telenet subsidiary, Laser Soft, in January 1991. Albeit losing many of its core members since 1994 when Telenet switched its focus to publishing Parlor games and doing contract development, Wolfteam remained an internal Telenet development team mostly working on Tales game series until it was merged into the jointly established Telenet/Namco subsidiary Namco Tales Studio in March 2003.','','81','0','','1986','1990','88849','47189','0','0','0000-00-00','0000-00-00','0','0');
